const express = require('express');
const session = require('express-session');
const bodyParser = require('body-parser');

const app = express();

// Middleware for parsing JSON bodies and handling sessions
app.use(bodyParser.json());
app.use(session({
  secret: 'your-session-secret',
  resave: false,
  saveUninitialized: true
}));

// Middleware to simulate user authentication
app.use((req, res, next) => {
  // Simulate a logged-in user
  if (!req.session.user) {
    req.session.user = { id: 1, username: 'userTester' }; // Example session data
  }
  next();
});

app.post('/delete-account', (req, res) => {
  if (!req.session.user) {
    return res.status(401).json({ message: 'Unauthorized' });
  }

  const { password } = req.body;
  
  // Placeholder for actual password verification with user credentials
  const isPasswordCorrect = password === 'userPassword123'; // Example password check

  if (!isPasswordCorrect) {
    return res.status(400).json({ message: 'Incorrect password' });
  }

  // Simulated account deletion process
  const userId = req.session.user.id;
  
  // Here you would integrate with your database to delete the user account
  console.log(`Deleting user with ID: ${userId}`);
  
  // Destroy session after account deletion
  req.session.destroy(err => {
    if (err) {
      return res.status(500).json({ message: 'Failed to delete account' });
    }
    res.status(200).json({ message: 'Account deleted successfully' });
  });
});

const PORT = 3000;
app.listen(PORT, () => console.log(`Server running on port ${PORT}`));